  ambessa: { diff: "EVEN", tone: "#e8b84b", tldr: "W-mist her dash combo \u2014 Snip her when her mobility is down.", breakdown: "Ambessa chains dashes and CC. W-mist her combo, and Snip her HP when her mobility is on cooldown.", dos: ["W-mist her dash combo", "Snip when her dashes are down", "E-reset to reposition"], donts: ["Trade into her full combo", "Chase her dashes out of mist", "Waste W on poke"], key: { slot: "E", name: "Repeating Dashes", cd: "12s", note: "Her mobility. Snip when it\u2019s down.", winT: "DASHES DOWN", winS: "Snip her in your mist." }, hold: "Hold W for her dash-chain all-in \u2014 mist her combo and Snip her on the cooldown.", tip: "Drop W as she commits her dash chain \u2014 her burst hits the mist while you Snip her HP down.", win: "W-mist her mobility and Snip her HP." },
